import{_ as n,o as t,c as i,ag as r}from"./chunks/framework.DXGyWiRo.js";const s="/images/uebung063.jpg",b=JSON.parse('{"title":"Übung Lektion 38","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung38.md","filePath":"lektionen/uebung38.md"}'),o={name:"lektionen/uebung38.md"};function u(a,e,l,p,c,h){return t(),i("div",null,[...e[0]||(e[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-38" tabindex="-1">Übung Lektion 38 <a class="header-anchor" href="#ubung-lektion-38" aria-label="Permalink to &quot;Übung Lektion 38&quot;">​</a></h1><p>A) Setzen Sie in folgenden Sätzen die entsprechende Form der Wörter in Klammern ein und übersetzen Sie:</p><p>... (सप्तमी विभक्तिः) ... धर्मं रक्षत्यभया जनाः ॥१॥ (राजन्)</p><blockquote><p>राज्ञि । राजनि धर्मं रक्षत्यभया जनाः ॥१॥<br> Wenn der König Recht und Sitte hütet, sind die Leute ohne Angst und Furcht.</p></blockquote><p>आसीद्राजपुत्रो गौतमस् ... सुकृतकर्मोप्पन्नो बुध्या रूप्यमितबलः ॥२॥ (नामन्)</p><blockquote><p>आसीद्राजपुत्रो गौतमो नाम सुकृतकर्मोप्पन्नो बुध्या रूप्यमितबलः ॥२॥<br> Es war einmal ein Königssohn - Gautama war sein Name - er hatte seine Aufgaben gut erfüllt, war voll Einsicht, schön, von unermesslicher Kraft.</p></blockquote><p>राज्यस्य ... (सप्तमी बहुवचने) ... अरयो राजानं योद्धुं तिष्ठन्ति ॥३॥ (सीमन्)</p><blockquote><p>राज्यस्य सीमस्वरयो राजानं योद्दुं तिषठन्ति ॥३॥<br> An den Grenzen des Reichs stehen Feinde, um den König zu bekämpfen.</p></blockquote><p>वैश्यानां कानि ... ॥४॥ (नामन्)</p><blockquote><p>वैश्यानां कानि नामानि ॥४॥<br> Was für Namen haben Vaiśyas?</p></blockquote><p>वैश्यास् ... ॥५॥ (किंनामन्)</p><blockquote><p>वश्याः किंनामानः ॥५॥<br> Was für Namen haben Vaiśyas?</p></blockquote><p>... (सप्तम्येकवचने) ... अकर्म यः पश्येदकर्मणि च कर्म यः स बुद्धिमान्मनुष्येषु स युक्त इति भगवद्गीतायाम् ॥६॥ (कर्मन्)</p><blockquote><p>कर्मण्यकर्म यः पश्येदकर्मणि च कर्म यः स बुद्धिमान्मनुष्येषु स युक्त इति भगवद्गीतायाम् ॥६॥<br> In der Bhagavadgītā steht, dass wer im Tun Nichttun und im Nichttun Tun sieht, weise unter den Menschen ist und ein Yogin.</p></blockquote><p>किम् ... किमकर्मेति कवयो ऽप्यत्र मोहिताः ॥७॥ (कर्मन्)</p><blockquote><p>किं कर्म किमकर्मेति कवयो ऽप्यत्र मोहिताः ॥७॥<br> Selbst Dichter sind darüber verwirrt worden, was Tun und was Nichttun ist.</p></blockquote><p>ब्रह्मभूतस् ... (प्रथमैकवचने) ... न शोचति न लुभ्यति ॥८॥ (प्रसन्नात्मन्)</p><blockquote><p>ब्रह्मभूतः प्रसन्नात्मा न शोचति न लुभ्यति ॥८॥<br> Wer zum Absoluten geworden ist, wessen Seele abgeklärt ist, der trauert nicht und begehrt nicht.</p></blockquote><p>... (षष्ठ्येकवचने) ... सुकृतस्य सुफलमाहुः ॥९॥ (कर्मन्)</p><blockquote><p>कर्मणः सुकृतस्य सुफलमाहुः ॥९॥<br> Man sagt, dass eine gut getane Tat eine gute Frucht bringt.</p></blockquote><p>महीभोगस् ... (शष्ठी बहुवचने) ... धर्मः ॥१०॥ (राजन्)</p><blockquote><p>महीभोगो राज्ञां धर्मः ॥११॥<br> Recht der Könige ist, die Welt zu genießen.</p></blockquote><p>रज्ञे ... दीयेरन् ॥११॥ (बलिन् हस्तिन्)</p><blockquote><p>रज्ञे बलिनो हस्तिनो दीयेरन् ॥११॥<br> Starke Elefanten soll man dem König geben.</p></blockquote><p>... (तृतीया विभक्तिः) ... लोका असृज्यन्त ॥१२॥ (ब्रह्मन् m.)</p><blockquote><p>ब्रह्मणा लोका असृजन्त ॥१२॥<br> Brahmā hat die Welten erschaffen.</p></blockquote><p>... (तृतीया विभक्तिः) ... कृतं पापं... (तृतीया विभक्तिः) ... अकृतं पापम् ॥१३॥ (आत्मन्)</p><blockquote><p>आत्मना कृतं पापमात्मनाकृतं पापम् ॥१३॥<br> Selbst tut man Böses, selbst unterlässt man Böses.</p></blockquote><p>सद्भिस् ... जनेभ्यो ऽभयं दीयते ॥१४॥ (राजन्)</p><blockquote><p>सद्भी रजाभिर्जनेभ्यो ऽभयं दीयते ॥१४॥<br> Gute Könige schenken den Menschen Furchtlosigkeit.</p></blockquote><p>... धर्मं न रक्षत्सु सभया जनाः ॥१५॥ (राजन्)</p><blockquote><p>राजसु धर्मं न रक्षत्सु सभया जनाः ॥१५॥<br> Wenn Könige Recht und Sitte nicht hüten, sind die Menschen voll Furcht.</p></blockquote><p><img src="'+s+'" alt=""><br> Abb.: रज्ञे बलिनो हस्तिनो दीयेरन्<br> Surin = สุรินทร, Thailand<br> [Bildquelle: how3ird. -- <a href="http://www.flickr.com/photos/how3ird/3103689757/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/how3ird/3103689757/</a>. -- Zugriff am 2009-01-20. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung)]</p><p>दश मूढाः</p><p>मूढानां चेष्टितानि प्रायेण विनोदावहानि । यथा हि -- एकदा दश मूढा देशाटनाय प्रस्थिताः । किञ्चिद्दूरं गतानां तेषामुपस्थिता काचिदगाधा नदी । बाहुभ्यां तरन्तस्ते कथमपि नदीं तीर्त्वा पारं गताः ॥</p><p>आसीत्तेषां मध्ये कश्चन वृद्धः । स किं सर्वे तीरमनुप्राप्ता ईति जिज्ञासमानस्तानेकैकशो गणयामास । परं नवैव परिगणितास्तेन । ततः स आक्रोशत् । अहो वयम् दश प्रस्थिताः । इदानीं नवैव स्मः । नूनमस्माकमेको नद्यां निमग्नः । गवेषयत तमिति । ततस्तेषामेकैको ऽपि गणनां चकार । परं नवैव दृश्यन्ते । ततस्तेषां व्याकुलीभूतानां महान्कोलाहलः समजनि । तत्रैव नातिदूरे कस्यचिदृषेराश्रमो ऽवर्तत । तत्र वसन्नृषिस्तेषां विवेष्टितमवलोक्योच्चैर्जहास । तस्य हासशब्दं श्रुत्वा मूढास्तरसा समुपसृत्य हासकारणमपृच्छन् । ऋषिराह । अहो । अनात्मज्ञा यूयम् । युष्माकमेकैको ऽपि नात्मानमगणयत् । तेनायं व्यामोहः संजात इति । तदाकर्ण्य ते मूढाः सलज्जमधोमुखाः प्रययुः ॥ (संस्कृतप्रथमादर्शः)</p><p>Zehn Deppen.</p><p>Das Treiben von Deppen ist meist unterhaltsam. So zum Beispiel: Einst sind sind zehn Deppen aufgebrochen, um im Land herumzuschweifen. Als sie ein Stück weit gegangen waren, stellte sich ihnen ein tiefer Fluss in den Weg. Mit den Armen rudernd haben sie irgendwie den Fluss überquert und sind ans andere Ufer gekommen.</p><p>Unter ihnen war ein Alter. Er wollte wissen, ob alle ans Ufer gekommen sind, und zählte darum jeden einzelnen. Aber er zählte nur neun. Da schrie er: &quot;Hallo! wir sind zu zehnt aufgebrochen, jetzt sind wir nur neun! Sicherlich ist einer im Fluss ertrunken! Sucht nach ihm!&quot; Daraufhin zählte jeder einzelne von ihnen nach. Aber es waren nur neun! Da wurden sie aufgeregt und es entstand ein großes Geschrei. Nicht weit von dort war die Einsiedelei eines Ṛṣi. Der dort wohnhafte betrachtete ihr Herumsuchen und lachte laut. Die Deppen hörten sein Gelächter, gingen schnell zu ihm und fragten ihn, warum er lache. Der Ṛṣi sagte: &quot;Ha! Ihr kennt euch selbst nicht. Jeder einzelne von euch hat sich selbst nicht mitgezählt. Deswegen ist diese Verwirrung entstanden.&quot; Als sie das hörten, sind die Deppen beschämt gesenkten Hauptes abgezogen.</p>',40)])])}const g=n(o,[["render",u]]);export{b as __pageData,g as default};
